```class Solution {
public:
    int maxScore(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        int res = 0, i = 0, j = nums.size() - 1;
        while (i < j) {
            res += (i + 1) * __gcd(nums[i], nums[j]);
            i++, j--;
        }
        return res;
    }
};
